import{c as o,Q as n,j as a,m as s}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"网络与多人同步:集成服务端、预测与插值","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/13-网络与多人同步-集成服务端预测与插值.md","filePath":"minecraftLearning/13-网络与多人同步-集成服务端预测与插值.md","lastUpdated":1781676649000}'),r={name:"minecraftLearning/13-网络与多人同步-集成服务端预测与插值.md"};function e(i,t,d,l,p,u){return n(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="网络与多人同步-集成服务端、预测与插值" tabindex="-1">网络与多人同步:集成服务端、预测与插值 <a class="header-anchor" href="#网络与多人同步-集成服务端、预测与插值" aria-label="Permalink to &quot;网络与多人同步:集成服务端、预测与插值&quot;">​</a></h1><p>先说一个会颠覆很多人认知的事实:<strong>你玩单机 Minecraft,本机也跑着一个完整的服务端。</strong></p><p>不是比喻。Java 版客户端在你点&quot;创建世界&quot;时,会在进程内启动一个 <code>IntegratedServer</code>(集成服务端),然后客户端通过一条<strong>内存里的假连接</strong>(loopback / <code>MemoryConnection</code>)连上它。世界生成、方块更新、实体 AI、刷怪、存盘——全发生在这个集成服务端里。客户端那一侧,几乎只负责<strong>渲染 + 收发包 + 一点点预测</strong>。</p><blockquote><p>一句话先记住:<strong>Minecraft 没有&quot;单机模式&quot;的特殊代码路径。单机 = 本机集成服务端 + loopback 客户端;联机 = 远程专用服务端 + TCP 客户端。两者跑的是同一套逻辑,区别只是连接的两端隔多远。</strong> 理解了这条,你就理解了为什么客户端永远是&quot;带预测的显示器&quot;,而不是世界本身。</p></blockquote><hr><h2 id="为什么要这么设计-单机也走-c-s" tabindex="-1">为什么要这么设计:单机也走 C/S <a class="header-anchor" href="#为什么要这么设计-单机也走-c-s" aria-label="Permalink to &quot;为什么要这么设计:单机也走 C/S&quot;">​</a></h2><p>直觉上,单机游戏直接在一个进程里跑逻辑+渲染最简单,何必拆成客户端连服务端?Mojang 选择&quot;单机也走客户端/服务端(C/S)&quot;是一个<strong>省维护成本</strong>的决定:</p><ul><li>只有一套世界逻辑代码。如果单机和联机各写一套,红石、刷怪、tick 的行为迟早会漂移。</li><li>单机里调通的机制,搬到联机几乎零改动——它本来就在&quot;服务端&quot;里跑。</li><li>代价:即使单机,玩家的输入也要打包&quot;发&quot;给本机服务端,世界状态再&quot;发&quot;回来渲染。loopback 连接没有网络延迟、不走真正的 socket(直接传对象引用),所以这点开销基本可忽略。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单机:</span></span>
<span class="line"><span>  ┌─────────────── 一个进程 ───────────────┐</span></span>
<span class="line"><span>  │  Client(渲染/输入)  ⇄ loopback ⇄  IntegratedServer(世界逻辑/存盘) │</span></span>
<span class="line"><span>  └────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>联机:</span></span>
<span class="line"><span>  Client(渲染/输入)  ⇄══ TCP ══⇄  DedicatedServer(世界逻辑/存盘)</span></span>
<span class="line"><span>       你的机器                         远程机器</span></span></code></pre></div><p><strong>客户端永远不持有&quot;真相&quot;。</strong> 它持有的是服务端发来的一份<strong>副本 + 自己猜的一点未来</strong>。这是后面所有&quot;为什么会橡皮筋&quot;&quot;为什么别人动得这么顺&quot;的总根源。</p><hr><h2 id="服务端权威-客户端只能-请求-不能-决定" tabindex="-1">服务端权威:客户端只能&quot;请求&quot;,不能&quot;决定&quot; <a class="header-anchor" href="#服务端权威-客户端只能-请求-不能-决定" aria-label="Permalink to &quot;服务端权威:客户端只能&quot;请求&quot;,不能&quot;决定&quot;&quot;">​</a></h2><p>Minecraft 是<strong>服务端权威(authoritative server)</strong> 模型:</p><table tabindex="0"><thead><tr><th>谁</th><th>能做什么</th></tr></thead><tbody><tr><td>客户端</td><td>发送<strong>意图</strong>:我按了前进、我左键挖这个方块、我把物品拖到这个槽</td></tr><tr><td>服务端</td><td><strong>裁决</strong>:你能不能动到那、那方块该不该破、那次交易合不合法,然后把<strong>结果</strong>广播给所有相关客户端</td></tr></tbody></table><p>举例:你左键一个石头。客户端不会自己把石头删掉,它发一个&quot;开始挖掘 / 挖掘完成&quot;的包给服务端;服务端校验(你够得着吗?手里工具对吗?保护区允许吗?)通过后,<strong>服务端</strong>把那格设为空气,再通过方块更新包告诉所有看得见这块的客户端。</p><p>这就是反作弊的底座:外挂能伪造客户端发什么包,但<strong>改不了服务端的裁决</strong>。一个&quot;瞬移外挂&quot;发一堆移动包,服务端发现你单 tick 位移超阈值,直接把你<strong>拉回</strong>合法位置(就是橡皮筋)。当然,服务端的校验并不完美(早期很多移动校验很松),但模型方向是对的:<strong>不信任客户端</strong>。</p><hr><h2 id="连接的一生-协议是分阶段的状态机" tabindex="-1">连接的一生:协议是分阶段的状态机 <a class="header-anchor" href="#连接的一生-协议是分阶段的状态机" aria-label="Permalink to &quot;连接的一生:协议是分阶段的状态机&quot;">​</a></h2><p>很多人以为&quot;联网&quot;就是一条管子一直发同一种包。实际上 Minecraft 协议是个<strong>状态机</strong>,连接会依次切换状态,<strong>每个状态有自己独立的一套包编号</strong>。同一个字节 <code>0x00</code> 在不同状态里是完全不同的包。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>握手 Handshake</span></span>
<span class="line"><span>   ├──→ Status   (服务器列表里那一行:延迟、在线人数、MOTD)→ 断开</span></span>
<span class="line"><span>   └──→ Login    (鉴权、加密、压缩协商、分配 UUID)</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>        Configuration   ← 1.20.2 新增的独立阶段</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>          Play           (真正进游戏后,绝大多数包都在这)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>阶段</th><th>干什么</th><th>关键点</th></tr></thead><tbody><tr><td><strong>Handshake</strong></td><td>客户端报一句&quot;我要去 Status 还是 Login&quot;</td><td>决定后续走哪条路</td></tr><tr><td><strong>Status</strong></td><td>拉服务器信息渲染那一行</td><td>多人界面的&quot;ping 一下&quot;,不进世界</td></tr><tr><td><strong>Login</strong></td><td>正版鉴权(对 Mojang/微软验证 session)、开启加密、协商压缩阈值、确定玩家 UUID</td><td>加密密钥在这建立</td></tr><tr><td><strong>Configuration</strong></td><td><strong>同步注册表、数据包、维度信息、服务器资源包</strong>,玩家此时还没进世界</td><td>见下</td></tr><tr><td><strong>Play</strong></td><td>玩家在世界里,移动/方块/实体/聊天/容器全在这</td><td>包量最大</td></tr></tbody></table><h3 id="configuration-阶段为什么单列出来" tabindex="-1">Configuration 阶段为什么单列出来 <a class="header-anchor" href="#configuration-阶段为什么单列出来" aria-label="Permalink to &quot;Configuration 阶段为什么单列出来&quot;">​</a></h3><p>1.20.2 之前,注册表同步这些&quot;进场前的准备&quot;是塞在 Play 阶段开头硬办的,导致<strong>重连、换维度、重载数据包</strong>时很别扭(得把人踢回去重来)。1.20.2 把它拆成独立的 <strong>Configuration 阶段</strong>:</p><ul><li>这里服务端把<strong>注册表</strong>发给客户端——还记得第 11 篇讲的 registry sync 吗?就在这一步。服务端说&quot;我的 1 号方块是 minecraft:stone&quot;,客户端据此对齐编号。<strong>对不上(版本/mod 不一致)就在这阶段失败,根本进不了 Play。</strong></li><li>动态注册表(生物群系、维度类型、由数据包定义的内容)也在这同步。</li><li>好处:之后想重新配置(比如服务端换了数据包),可以把客户端<strong>从 Play 切回 Configuration</strong> 再切回来,不用断线重连。</li></ul><hr><h2 id="进了世界之后-服务端到底发什么" tabindex="-1">进了世界之后:服务端到底发什么 <a class="header-anchor" href="#进了世界之后-服务端到底发什么" aria-label="Permalink to &quot;进了世界之后:服务端到底发什么&quot;">​</a></h2><p>Play 阶段的包大致分几类,理解它们就理解了&quot;客户端看到的世界是怎么拼出来的&quot;:</p><table tabindex="0"><thead><tr><th>包类(方向)</th><th>内容</th></tr></thead><tbody><tr><td>区块数据(S→C)</td><td>一个 chunk 的方块(palette 压缩的 section)+ 光照,一次性发过来让客户端建 mesh</td></tr><tr><td>方块更新(S→C)</td><td>单格变化 / 一个 section 批量变化,增量打补丁</td></tr><tr><td>实体生成/移动(S→C)</td><td>实体出现、销毁,以及<strong>位置增量</strong></td></tr><tr><td>实体元数据(S→C)</td><td>血量、姿势、燃烧、命名等状态变化</td></tr><tr><td>玩家输入(C→S)</td><td>移动、视角、挖掘、使用、攻击、切换物品</td></tr><tr><td>容器/菜单(双向)</td><td>打开容器、点击槽位、确认事务</td></tr></tbody></table><h3 id="区块与光照-为什么进新区域会-卡一下糊一下" tabindex="-1">区块与光照:为什么进新区域会&quot;卡一下糊一下&quot; <a class="header-anchor" href="#区块与光照-为什么进新区域会-卡一下糊一下" aria-label="Permalink to &quot;区块与光照:为什么进新区域会&quot;卡一下糊一下&quot;&quot;">​</a></h3><p>你走到没加载过的地方,服务端把那批 chunk 的方块和光照打包发来。客户端收到后还要<strong>在本地建 mesh</strong>(第 3 篇讲的&quot;只画看得见的面&quot;)。所以新区域有两步开销:<strong>网络收包 + 本地建网格</strong>。区块多、网慢,或者本地建 mesh 排队,就表现为地形一块块&quot;长&quot;出来。</p><p>注意:<strong>光照值也是服务端算好发过来的</strong>(第 10 篇的双通道光照),客户端默认不重算——这样大家看到的明暗一致。</p><h3 id="实体移动-你看到的-别人-是插出来的" tabindex="-1">实体移动:你看到的&quot;别人&quot;,是插出来的 <a class="header-anchor" href="#实体移动-你看到的-别人-是插出来的" aria-label="Permalink to &quot;实体移动:你看到的&quot;别人&quot;,是插出来的&quot;">​</a></h3><p>这是最值得讲清的反直觉点。服务端 20 TPS,每 50ms 才更新一次实体位置,而且为了省带宽,发的还是<strong>增量</strong>(相对上次的位移),甚至不是每 tick 都发。如果客户端&quot;收到一个位置就把实体瞬移过去&quot;,你会看到所有人都在<strong>抽搐式跳格</strong>(每 50ms 跳一下)。</p><p>所以客户端做<strong>插值(interpolation)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>服务端发来的离散位置:   t0 ●            t1 ●            t2 ●</span></span>
<span class="line"><span>客户端实际渲染(60fps): ●·····●·····●·····●·····●·····●·····●</span></span>
<span class="line"><span>                        └── 在两个收到的位置之间平滑补帧 ──┘</span></span></code></pre></div><p>客户端把收到的目标位置当&quot;我要在接下来几帧里滑过去的终点&quot;,于是别人的移动看起来丝滑。<strong>代价:你看到的别人,永远是过去某一刻的位置 + 一段猜测,不是此刻服务端的真实位置。</strong> PVP 里这点很要命——你瞄准的是对方&quot;显示出来&quot;的身位,服务端判定却用它那边的真实坐标,延迟越高错位越大。</p><h3 id="你自己-预测-回正-橡皮筋" tabindex="-1">你自己:预测 + 回正(橡皮筋) <a class="header-anchor" href="#你自己-预测-回正-橡皮筋" aria-label="Permalink to &quot;你自己:预测 + 回正(橡皮筋)&quot;">​</a></h3><p>对<strong>别人</strong>插值,对<strong>自己</strong>则不能——你按前进键,总不能等一个网络往返(发包→服务端→收回)才开始动,那操作会有明显延迟。所以客户端对自己做<strong>预测(client-side prediction)</strong>:</p><ol><li>你按前进,客户端<strong>立刻</strong>让你向前移动并渲染(本地先行)。</li><li>同时把这次输入发给服务端。</li><li>服务端用它那边的世界裁决你的真实位置,发回&quot;权威坐标&quot;。</li><li>客户端对比:如果和自己预测的一致(绝大多数情况),无感;如果<strong>对不上</strong>(你预测穿墙了、服务端那有个你不知道的方块、网络丢包),服务端的坐标覆盖你的预测——你被<strong>拽回去</strong>。</li></ol><p>这就是<strong>橡皮筋(rubberbanding)</strong>:本质是&quot;客户端预测错了,被服务端权威回正&quot;。卡顿、丢包、或服务端 TPS 掉时最明显,因为预测和权威差得越来越远。</p><hr><h2 id="tick-20-与包频率-不是一回事" tabindex="-1">tick(20)与包频率:不是一回事 <a class="header-anchor" href="#tick-20-与包频率-不是一回事" aria-label="Permalink to &quot;tick(20)与包频率:不是一回事&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时钟</th><th>频率</th><th>谁的</th></tr></thead><tbody><tr><td>服务端 tick</td><td>20 TPS(50ms)</td><td>世界逻辑推进的节拍</td></tr><tr><td>渲染帧</td><td>你的显示器能跑多少(60/144…)</td><td>纯客户端,和服务端无关</td></tr><tr><td>包发送</td><td>跟着 tick,但不是每个状态每 tick 都发</td><td>按需 + 增量,省带宽</td></tr></tbody></table><p>服务端逻辑永远 20 TPS。但<strong>包不会傻发</strong>:实体没动就不发它的移动包;位置增量小用短包,大跳变才发全量。客户端 60+ fps 渲染靠插值/预测把 20 TPS 的离散状态&quot;抹&quot;成连续画面。</p><p><strong>所以服务端掉 TPS 时会发生什么?</strong> 还记得第 4 篇:服务端单 tick 算不完就拖时。它一拖,<strong>发包也跟着稀疏</strong>——实体更新变慢、方块变化延迟到达。客户端这边帧率可能还是 144fps 很流畅,但世界&quot;内容&quot;卡住了:怪物顿挫、你打方块半天不破、橡皮筋频发。<strong>FPS 高 ≠ 不卡,卡的是服务端的 tick,不是你的显卡。</strong> 这也是为什么联机体验差时该去看服务端 MSPT,而不是本地帧数。</p><hr><h2 id="方块更新和容器-也全是包" tabindex="-1">方块更新和容器:也全是包 <a class="header-anchor" href="#方块更新和容器-也全是包" aria-label="Permalink to &quot;方块更新和容器:也全是包&quot;">​</a></h2><p>别忘了世界里&quot;非移动&quot;的交互同样走这套:</p><ul><li><strong>方块更新</strong>:服务端裁决后发方块变化包,客户端打补丁并重建受影响 chunk 的 mesh。你放下一个方块时,客户端可能也做了一点本地预测(立刻显示),但仍以服务端结果为准。</li><li><strong>容器/菜单</strong>:第 11 篇讲过,打开箱子时服务端临时建一个 Menu,把槽位<strong>同步</strong>给客户端。你拖动物品其实是发&quot;点击槽位&quot;的包,服务端裁决物品怎么移动再同步回来——这里历史上有一套&quot;事务确认&quot;机制防止客户端和服务端的背包状态对不上(对不上就强制重发整个容器)。所以<strong>容器本质也是一段服务端权威、客户端显示的同步会话</strong>,和移动是同一个哲学。</li></ul><hr><h2 id="踩坑与反直觉" tabindex="-1">踩坑与反直觉 <a class="header-anchor" href="#踩坑与反直觉" aria-label="Permalink to &quot;踩坑与反直觉&quot;">​</a></h2><ul><li><strong>&quot;单机没有网络问题&quot;是错的</strong>:单机也走 C/S,只是 loopback 没延迟。所以单机里 TPS 掉了,你照样会看到怪物顿挫——因为客户端依旧在等服务端的包,只不过服务端就在隔壁内存里。</li><li><strong>别人移动顺滑 ≠ 网络好</strong>:那是插值在帮忙。真实延迟体现在&quot;你的动作多久被世界确认&quot;(打人、开门、橡皮筋),不体现在别人滑得顺不顺。</li><li><strong>高 FPS 不能掩盖低 TPS</strong>:两套时钟。渲染流畅但世界卡,几乎一定是服务端 tick 的问题。</li><li><strong>改了客户端也改不了世界</strong>:服务端权威。客户端 mod 能改你&quot;看到&quot;什么、怎么渲染,但方块、实体、物品的真相在服务端,联机时由服务端说了算。</li><li><strong>进服卡在&quot;正在加入世界&quot;</strong>:多半是 Configuration 阶段注册表/数据包对不齐(版本或 mod 不一致),不是网慢。</li></ul><hr><h2 id="串联" tabindex="-1">串联 <a class="header-anchor" href="#串联" aria-label="Permalink to &quot;串联&quot;">​</a></h2><p>这一篇把前面所有&quot;服务端内部&quot;的内容接到了玩家屏幕上:第 4 篇的 20 TPS 决定了包的节拍和掉 TPS 时的体验;第 3 篇的区块 mesh 是在客户端收到区块包后才建的;第 10 篇的光照是服务端算好发来的;第 11 篇的注册表同步发生在 Configuration 阶段、菜单会话靠包驱动。一句话收口:<strong>服务端是唯一的&quot;世界&quot;,客户端是它一个带预测的、略微滞后的影子。</strong> 你玩的从来不是本地那份画面,而是服务端那份状态的转播。</p>`,55)])])}const c=o(r,[["render",e]]);export{h as __pageData,c as default};
